# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<Ticket> Tickets { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseSqlServer(@"Data Source=(localdb)\mssqllocaldb;Initial Catalog=EventBookingDB;Integrated Security=True");
    }
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int TotalSeats { get; set; }
}

public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public int Quantity { get; set; }
}

public class Program
{
    public static async Task PurchaseTicketsAsync(int eventId, int quantity)
    {
        using (var context = new EventBookingContext())
        {
            var eventEntity = await context.Events.FindAsync(eventId);
            if (eventEntity == null || eventEntity.TotalSeats < quantity)
                throw new Exception("Event not found or insufficient seats");

            var ticketEntity = await context.Tickets.FindAsync(eventId);
            if (ticketEntity != null && ticketEntity.Quantity >= quantity)
                throw new Exception("Insufficient tickets available");

            try
            {
                await context.Database.ExecuteSqlRawAsync($"UPDATE Events SET TotalSeats = TotalSeats - {quantity} WHERE Id = @eventId", new SqlParameter("@eventId", eventId));
                await context.Database.ExecuteSqlRawAsync($"INSERT INTO Tickets (EventId, Quantity) VALUES (@eventId, @quantity)", new SqlParameter("@eventId", eventId), new SqlParameter("@quantity", quantity));
            }
            catch (Exception ex)
            {
                throw new Exception("Failed to update inventory: " + ex.Message);
            }
        }
    }

    public static async Task Main(string[] args)
    {
        await PurchaseTicketsAsync(1, 10);
    }
}